function sf_qa_root(): string { return realpath(__DIR__ . '/..') ?: dirname(__DIR__); }
function sf_qa_h($value): string { return sf_admin_h($value); }
function sf_qa_rel_path(string $path): string { return ltrim(str_replace('\\', '/', $path), '/'); }
function sf_qa_file_path(string $relative): string { return sf_qa_root() . '/' . sf_qa_rel_path($relative); }
function sf_qa_file_exists(string $relative): bool { return is_file(sf_qa_file_path($relative)); }
function sf_qa_dir_exists(string $relative): bool { return is_dir(sf_qa_file_path($relative)); }
function sf_qa_read_file(string $relative): string { $path = sf_qa_file_path($relative); return is_file($path) ? (string)file_get_contents($path) : ''; }
function sf_qa_contains(string $relative, array $needles): bool { $body = sf_qa_read_file($relative); if ($body === '') return false; foreach ($needles as $needle) if ($needle !== '' && strpos($body, $needle) !== false) return true; return false; }
function sf_qa_db_ready(): bool { return sf_db() instanceof PDO; }
function sf_qa_table_exists(string $table): bool { return sf_admin_table_exists($table); }
function sf_qa_columns(string $table): array { return sf_admin_table_columns($table); }
function sf_qa_status(string $status, string $label, string $detail = '', int $weight = 1): array { return ['status'=>$status,'label'=>$label,'detail'=>$detail,'weight'=>max(1,$weight)]; }
function sf_qa_score(array $checks): int { $points=0.0; $total=0.0; foreach($checks as $check){ $weight=(int)($check['weight']??1); $total+=$weight; $status=(string)($check['status']??'fail'); if(in_array($status,['pass','ready','ok'],true))$points+=$weight; elseif(in_array($status,['warn','preview','manual'],true))$points+=$weight*.7; elseif($status==='info')$points+=$weight*.5; } return $total>0?(int)round(($points/$total)*100):0; }
function sf_qa_grade(int $score): string { if($score>=97)return '10/10'; if($score>=90)return '9/10'; if($score>=80)return '8/10'; if($score>=70)return '7/10'; return 'Needs work'; }
function sf_qa_badge(string $status): string { $map=['pass'=>'active','ready'=>'active','ok'=>'active','warn'=>'draft','preview'=>'draft','manual'=>'draft','info'=>'draft','fail'=>'canceled','missing'=>'canceled']; return sf_admin_status_badge($map[$status] ?? $status); }
